async function batchDelete(ids) {
  if (!Array.isArray(ids) || ids.length === 0) {
    throw new Error('Invalid or empty IDs array');
  }

  const deletedIds = [];
  const errors = [];

  try {
    // Start a transaction
    await db.query('BEGIN');

    for (const id of ids) {
      try {
        await db.query('DELETE FROM records WHERE id = $1', [id]);
        deletedIds.push(id);
      } catch (error) {
        errors.push({ id, error: error.message });
      }
    }

    // If there were any errors, roll back the transaction
    if (errors.length > 0) {
      await db.query('ROLLBACK');
      throw new Error('One or more deletions failed');
    }

    // If all deletions were successful, commit the transaction
    await db.query('COMMIT');
  } catch (error) {
    // Log the error for debugging purposes
    console.error('Transaction failed:', error.message);
    // Roll back the transaction if it's still active
    await db.query('ROLLBACK');
    throw error;
  }

  return {
    deleted: deletedIds.length,
    deletedIds,
    errors,
  };
}
```

